:root { --bg:#fff; --fg:#111; --accent:#5eead4; }
* { box-sizing: border-box; margin: 0; padding: 0; }
body { background: var(--bg); color: var(--fg); font-family: system-ui, sans-serif; }
.topbar { display:flex; justify-content:space-between; padding: 16px 32px; }
.hero { padding: 120px 32px; text-align: center; }
